import{_ as e,c as o,o as r,ag as s}from"./chunks/framework.DD2hp6gW.js";const h=JSON.parse('{"title":"Option Groups","description":"","frontmatter":{},"headers":[],"relativePath":"option-groups.md","filePath":"option-groups.md","lastUpdated":1777110900000}'),a={name:"option-groups.md"};function i(n,t,l,u,d,g){return r(),o("div",null,t[0]||(t[0]=[s('<h1 id="option-groups" tabindex="-1">Option Groups <a class="header-anchor" href="#option-groups" aria-label="Permalink to &quot;Option Groups&quot;">​</a></h1><p><strong>Option Groups</strong> are the building blocks of OptionBay. Instead of creating options for every product individually, you create reusable &quot;groups&quot; that can be assigned to multiple products, categories, or tags. This modular approach saves time and ensures consistency across your store.</p><h2 id="creating-an-option-group" tabindex="-1">Creating an Option Group <a class="header-anchor" href="#creating-an-option-group" aria-label="Permalink to &quot;Creating an Option Group&quot;">​</a></h2><p>To create your first group:</p><ol><li>Navigate to <strong>Products &gt; Options</strong> in your WordPress dashboard.</li><li>Click the <strong>Add New</strong> button at the top.</li><li>Enter a <strong>Title</strong> for your group (e.g., &quot;Gift Wrapping Options&quot; or &quot;Technical Specifications&quot;). This title is for your internal reference and is not shown to customers.</li><li>Use the <strong><a href="./builder.html">Addon Builder</a></strong> to add fields to your group.</li><li>Configure the <strong><a href="./assignments.html">Product Assignments</a></strong> to decide where these options should appear.</li><li>Click <strong>Save</strong> to publish the group.</li></ol><h2 id="managing-your-groups" tabindex="-1">Managing Your Groups <a class="header-anchor" href="#managing-your-groups" aria-label="Permalink to &quot;Managing Your Groups&quot;">​</a></h2><p>The main Options page provides an overview of all your created groups in a WordPress-style list table.</p><h3 id="group-overview-table" tabindex="-1">Group Overview Table <a class="header-anchor" href="#group-overview-table" aria-label="Permalink to &quot;Group Overview Table&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Column</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Title</strong></td><td style="text-align:left;">The internal name of the group. Click to edit.</td></tr><tr><td style="text-align:left;"><strong>Status</strong></td><td style="text-align:left;">Whether the group is currently <strong>Published</strong> (live on the store) or saved as a <strong>Draft</strong>.</td></tr></tbody></table><h3 id="row-actions" tabindex="-1">Row Actions <a class="header-anchor" href="#row-actions" aria-label="Permalink to &quot;Row Actions&quot;">​</a></h3><p>When you hover over a group in the list, the following actions appear:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Action</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Edit</strong></td><td style="text-align:left;">Opens the Addon Builder for this group so you can modify fields, pricing, and logic.</td></tr><tr><td style="text-align:left;"><strong>Duplicate</strong></td><td style="text-align:left;">Creates an exact copy of the group, including all fields, options, pricing, and assignment rules. Useful for creating variations of complex sets.</td></tr><tr><td style="text-align:left;"><strong>Delete</strong></td><td style="text-align:left;">Permanently removes the group and all its associated assignments. This action cannot be undone.</td></tr></tbody></table><h2 id="group-status" tabindex="-1">Group Status <a class="header-anchor" href="#group-status" aria-label="Permalink to &quot;Group Status&quot;">​</a></h2><p>Each group has a status that determines its visibility:</p><ul><li><strong>Published:</strong> The group is live and will appear on products that match its assignment rules.</li><li><strong>Draft:</strong> The group is saved but will <strong>not</strong> be displayed on the frontend. Use this while you&#39;re still building or testing your options.</li></ul><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>Use the <strong>Draft</strong> status while building complex option groups with conditional logic. This way, you can save your work in progress without customers seeing unfinished options on your store.</p></div><h2 id="best-practices" tabindex="-1">Best Practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best Practices&quot;">​</a></h2><ul><li><strong>Keep it Modular:</strong> Instead of one massive group with 50 fields, break them into smaller, focused groups (e.g., &quot;Basic Personalization&quot; and &quot;Premium Addons&quot;). This makes management easier and allows you to reuse individual groups across different products.</li><li><strong>Clear Naming:</strong> Use descriptive titles for your groups (e.g., &quot;T-Shirt Customization&quot; rather than &quot;Group 1&quot;) so you can easily identify them when setting up assignment rules.</li><li><strong>Test with Draft Mode:</strong> Always preview your options by switching the group to &quot;Published&quot; on a test product before going live on your entire catalog.</li></ul><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="./builder.html">Learn how to use the Addon Builder</a></li><li><a href="./assignments.html">Configure Product Assignments</a></li></ul>',20)]))}const c=e(a,[["render",i]]);export{h as __pageData,c as default};
